from pathlib import Path
import openpyxl
import re
from datetime import datetime


def verify(workspace_path, external_services_path=None):
    workspace = Path(workspace_path)

    xlsx_files = list(workspace.glob('**/PBC_Denial_Worklist*'))
    if not xlsx_files:
        xlsx_files = list(workspace.glob('**/*Denial_Worklist*'))
    if not xlsx_files:
        xlsx_files = [f for f in workspace.glob('**/*.xlsx')
                      if 'denial' in f.name.lower() or 'worklist' in f.name.lower()]
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No PBC_Denial_Worklist.xlsx found in workspace'}

    required_ids = {
        'HIC-19887899', 'HIC-19887900', 'HIC-19887901',
        'HIC-25124778', 'HIC-25124779', 'HIC-25124780',
        'HIC-26877757', 'HIC-26877758', 'HIC-26877795'
    }

    best_result = {'pass': False, 'score': 0.0, 'feedback': 'No matching claim IDs found in denial worklist'}

    for xlsx_file in xlsx_files:
        try:
            wb = openpyxl.load_workbook(xlsx_file, data_only=True)
        except Exception:
            continue

        for sheet in wb.worksheets:
            # Detect column positions from the header row so layout changes don't break checks
            col_map = {}
            for cell in sheet[1]:
                if cell.value:
                    key = str(cell.value).strip().lower()
                    col_map[key] = cell.column - 1  # 0-based index into row_vals

            # Fall back to known fixed positions if headers are absent or renamed
            cat_col    = col_map.get('category',        col_map.get('denial_category', 0))
            id_col     = col_map.get('claim_id',                                        1)
            code_col   = col_map.get('co_code',         col_map.get('denial_code',      2))
            action_col = col_map.get('recovery_action', col_map.get('action',           3))
            date_col   = col_map.get('date_received',   col_map.get('date',             4))
            status_col = col_map.get('recovery_status', col_map.get('status',           5))

            found_ids = set()
            issues = []

            for row in sheet.iter_rows(min_row=2, max_row=100, values_only=False):
                raw_vals = [cell.value for cell in row]
                row_vals = []
                for v in raw_vals:
                    if v is None:
                        row_vals.append('')
                    elif isinstance(v, datetime):
                        row_vals.append(v.strftime('%m/%d/%Y'))
                    else:
                        row_vals.append(str(v).strip())

                # Identify which target claim ID appears in this row
                row_id = None
                for rid in required_ids:
                    rid_lower = rid.lower()
                    rid_nodash = rid_lower.replace('-', '')
                    for v in row_vals:
                        v_lower = v.lower()
                        if rid_lower in v_lower or rid_nodash in v_lower.replace('-', ''):
                            row_id = rid
                            break
                    if row_id:
                        break
                if row_id is None:
                    continue
                found_ids.add(row_id)

                # --- Category: check the Category column value ONLY ---
                # Intentionally NOT searching the combined row string — 'contractual'
                # appearing in the action field ('Appeal - Contractual Rate Dispute')
                # must not satisfy the category check.
                cat_val = row_vals[cat_col] if cat_col < len(row_vals) else ''
                cat_ok = (
                    'contractual/payer error' in cat_val.lower() or
                    ('contractual' in cat_val.lower() and 'payer' in cat_val.lower()) or
                    'payer error' in cat_val.lower()
                )

                # --- CO code: check the CO_Code column value ONLY ---
                code_val = row_vals[code_col] if code_col < len(row_vals) else ''
                code_clean = code_val.lower().replace(' ', '').replace('-', '')
                code_ok = code_clean in ('co45', '45') or 'co45' in code_clean

                # --- Recovery action: check the action column value ONLY ---
                action_val = row_vals[action_col] if action_col < len(row_vals) else ''
                action_ok = 'appeal' in action_val.lower() and (
                    'contractual' in action_val.lower() or 'rate dispute' in action_val.lower()
                )

                # --- Date: check the date column value ONLY ---
                date_val = row_vals[date_col] if date_col < len(row_vals) else ''
                date_variants = ['02/17/2026', '2/17/2026']
                date_ok = any(d in date_val for d in date_variants)
                if not date_ok:
                    raw_date = raw_vals[date_col] if date_col < len(raw_vals) else None
                    if isinstance(raw_date, datetime):
                        date_ok = (raw_date.month == 2 and raw_date.day == 17
                                   and raw_date.year == 2026)

                # --- Status: check the status column value ONLY ---
                status_val = row_vals[status_col] if status_col < len(row_vals) else ''
                status_ok = 'escalated' in status_val.lower()

                row_issues = []
                if not cat_ok:
                    row_issues.append(f"category={cat_val!r} (expected 'Contractual/Payer Error')")
                if not code_ok:
                    row_issues.append(f"co_code={code_val!r} (expected CO-45)")
                if not action_ok:
                    row_issues.append(f"action={action_val!r} (expected 'Appeal - Contractual Rate Dispute')")
                if not date_ok:
                    row_issues.append(f"date={date_val!r} (expected 02/17/2026)")
                if not status_ok:
                    row_issues.append(f"status={status_val!r} (expected to contain 'Escalated')")
                if row_issues:
                    issues.append(f"{row_id}: {'; '.join(row_issues)}")

            missing_ids = required_ids - found_ids
            all_found = len(found_ids) == 9
            no_issues = len(issues) == 0

            score = round(min(len(found_ids) / 9.0 * (1.0 if no_issues else 0.5), 1.0), 3)
            result = {
                'pass': all_found and no_issues,
                'score': score,
                'feedback': (
                    f'Found {len(found_ids)}/9 claim IDs in {xlsx_file.name}.'
                    + (f' Missing: {sorted(missing_ids)}.' if missing_ids else '')
                    + (f' Field issues: {issues}' if issues else ' All fields correct.')
                )
            }
            if result['score'] > best_result['score']:
                best_result = result
            if result['pass']:
                return result

    return best_result

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # Check external services path first, then workspace
    paths_to_check = []
    if external_services_path:
        paths_to_check.append(Path(external_services_path) / 'mailbox.json')
    paths_to_check.append(Path(workspace_path) / 'mailbox.json')

    for mailbox_path in paths_to_check:
        if not mailbox_path.exists():
            continue
        try:
            with open(mailbox_path) as f:
                data = json.load(f)
            emails = data.get('emails', [])

            # The rubric says: exactly 1 email in draft to no one ("to_addr": empty or NULL)
            # This means we need a draft email where to_addr is empty or null
            draft_emails_no_to = []
            for email in emails:
                folder = str(email.get('folder', '')).lower().strip()
                to_addr = email.get('to_addr', None)

                is_draft = 'draft' in folder
                # to_addr should be empty or NULL
                to_empty = (
                    to_addr is None
                    or str(to_addr).strip() == ''
                    or str(to_addr).strip().lower() == 'null'
                    or str(to_addr).strip().lower() == 'none'
                    or to_addr == []
                )

                if is_draft and to_empty:
                    draft_emails_no_to.append(email)

            if len(draft_emails_no_to) == 1:
                target = draft_emails_no_to[0]
                return {
                    'pass': True,
                    'score': 1.0,
                    'feedback': f'Found exactly 1 draft email with empty/null to_addr. Email ID: {target.get("email_id")}, from: {target.get("from_addr")}, subject: {target.get("subject")}'
                }
            elif len(draft_emails_no_to) == 0:
                # Also check for drafts more loosely - maybe to_addr is present but it's a new draft
                all_drafts = [e for e in emails if 'draft' in str(e.get('folder', '')).lower()]
                if all_drafts:
                    details = []
                    for d in all_drafts:
                        details.append(f'Email ID {d.get("email_id")}: from={d.get("from_addr")}, to={d.get("to_addr")}')
                    return {
                        'pass': False,
                        'score': 0.0,
                        'feedback': f'Found {len(all_drafts)} draft email(s) but none have empty/null to_addr. Drafts found: ' + '; '.join(details)
                    }
                else:
                    return {
                        'pass': False,
                        'score': 0.0,
                        'feedback': 'No draft emails found in mailbox.json'
                    }
            else:
                details = []
                for d in draft_emails_no_to:
                    details.append(f'Email ID {d.get("email_id")}: from={d.get("from_addr")}, to={d.get("to_addr")}')
                return {
                    'pass': False,
                    'score': 0.0,
                    'feedback': f'Expected exactly 1 draft email with empty/null to_addr, found {len(draft_emails_no_to)}: ' + '; '.join(details)
                }
        except Exception as e:
            continue
    return {'pass': False, 'score': 0.0, 'feedback': 'mailbox.json not found or unreadable in any checked path'}

from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    # Try to find escalation log files with increasingly broad patterns
    xlsx_files = list(Path(workspace_path).glob('*Escalation_Log*'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('*escalation*log*'))
    if not xlsx_files:
        xlsx_files = [f for f in Path(workspace_path).glob('*.xlsx') if 'escalation' in f.name.lower() or 'esc' in f.name.lower()]
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No xlsx file found in workspace'}

    required_claim_ids = [
        'HIC-19887899', 'HIC-19887900', 'HIC-19887901',
        'HIC-25124778', 'HIC-25124779', 'HIC-25124780',
        'HIC-26877757', 'HIC-26877758', 'HIC-26877795'
    ]

    def check_date_present(text):
        """Check for 02/17/2026 or similar date formats."""
        date_patterns = [
            r'02[/\-.]17[/\-.]2026',
            r'2[/\-.]17[/\-.]2026'
        ]
        for pat in date_patterns:
            if re.search(pat, text, re.IGNORECASE):
                return True
        return False

    def check_row(row_vals):
        """Check a row for all required fields. Returns (pass, details_dict)."""
        row_str = ' '.join(row_vals)
        row_str_lower = row_str.lower()

        # Check Claim_IDs - at least some of the required claim IDs should be present
        found_claims = [cid for cid in required_claim_ids if cid.lower() in row_str_lower]
        has_claim_ids = len(found_claims) >= 5  # at least majority present (be lenient)

        has_payer_id = 'a4789p' in row_str_lower
        has_operational = 'operational' in row_str_lower
        has_pattern_recurrence = 'pattern recurrence' in row_str_lower or ('pattern' in row_str_lower and 'recur' in row_str_lower)

        # Resolution_Tkg: 'RCM Manager on 02/17/2026'
        # Accept variations: "RCM Manager", date present
        has_manager_ref = 'rcm manager' in row_str_lower
        has_date = check_date_present(row_str)
        # Also accept notified/escalated language as part of resolution
        has_notified_or_escalated = (
            'notified' in row_str_lower or 'notify' in row_str_lower or 'notification' in row_str_lower or
            'escalated' in row_str_lower or 'escalate' in row_str_lower or 'escalation' in row_str_lower or
            ' on ' in row_str_lower  # "RCM Manager on 02/17/2026"
        )
        has_resolution = has_manager_ref and has_date

        details = {
            'Claim_IDs': has_claim_ids,
            'A4789P': has_payer_id,
            'Operational': has_operational,
            'Pattern Recurrence': has_pattern_recurrence,
            'RCM Manager in Resolution': has_manager_ref,
            'date in Resolution': has_date,
        }
        total = len(details)
        matched = sum(1 for v in details.values() if v)
        all_pass = all(details.values())
        return all_pass, details, matched / total, found_claims

    best_score = 0.0
    best_feedback = ''

    for xlsx_file in xlsx_files:
        try:
            wb = openpyxl.load_workbook(xlsx_file, data_only=True)
        except Exception as e:
            continue
        for sheet in wb.worksheets:
            # First check row 3 specifically (as rubric states)
            if sheet.max_row >= 3:
                row3 = sheet[3]
                row_vals = [str(cell.value).strip() if cell.value is not None else '' for cell in row3]
                all_pass, details, score, found_claims = check_row(row_vals)
                if all_pass:
                    return {'pass': True, 'score': 1.0, 'feedback': f'Row 3 in {xlsx_file.name} contains all required escalation fields: Claim IDs ({len(found_claims)} found), A4789P, Operational, Pattern Recurrence, and Resolution with RCM Manager on 02/17/2026. Values: {row_vals}'}
                else:
                    found = [k for k, v in details.items() if v]
                    missing = [k for k, v in details.items() if not v]
                    if score > best_score:
                        best_score = score
                        best_feedback = f'Row 3 in {xlsx_file.name}: Found={found}, Missing={missing}. Claims found: {found_claims}. Row values: {row_vals}'

            # Then check all rows as fallback (agent may have inserted at a different row)
            for row_idx in range(1, sheet.max_row + 1):
                if row_idx == 3:
                    continue  # already checked
                row = sheet[row_idx]
                row_vals = [str(cell.value).strip() if cell.value is not None else '' for cell in row]
                all_pass, details, score, found_claims = check_row(row_vals)
                if all_pass:
                    return {'pass': True, 'score': 1.0, 'feedback': f'Escalation row found in {xlsx_file.name} row {row_idx} (not row 3 but contains all required fields): Claim IDs ({len(found_claims)} found), A4789P, Operational, Pattern Recurrence, RCM Manager on 02/17/2026. Values: {row_vals}'}
                else:
                    found = [k for k, v in details.items() if v]
                    missing = [k for k, v in details.items() if not v]
                    if score > best_score:
                        best_score = score
                        best_feedback = f'Row {row_idx} in {xlsx_file.name}: Found={found}, Missing={missing}. Claims found: {found_claims}. Row values: {row_vals}'

    if best_score > 0:
        return {'pass': False, 'score': min(best_score, 0.5), 'feedback': f'Partial match found but not all required fields present. Best match: {best_feedback}'}

    return {'pass': False, 'score': 0.0, 'feedback': f'No escalation row with required Claim IDs, A4789P, Operational, Pattern Recurrence, RCM Manager on 02/17/2026 found. Files checked: {[f.name for f in xlsx_files]}'}

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    # Target only the Escalation Log - do not fall back to all PBC files
    workspace = Path(workspace_path)
    xlsx_files = list(workspace.glob('*Escalation_Log*.xlsx'))
    if not xlsx_files:
        xlsx_files = list(workspace.glob('*escalation*log*.xlsx'))
    if not xlsx_files:
        xlsx_files = [f for f in workspace.glob('*.xlsx') if 'escalation' in f.name.lower()]
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'PBC_Escalation_Log.xlsx not found in workspace'}

    required_ids = [
        'HIC-19887899', 'HIC-19887900', 'HIC-19887901',
        'HIC-25124778', 'HIC-25124779', 'HIC-25124780',
        'HIC-26877757', 'HIC-26877758', 'HIC-26877795'
    ]

    # Collect results across all matching files; do NOT return early on failure
    best_result = {'pass': False, 'score': 0.0, 'feedback': 'No matching escalation log found'}

    for xlsx_file in xlsx_files:
        try:
            wb = openpyxl.load_workbook(str(xlsx_file), data_only=True)
        except Exception as e:
            continue

        for sheet in wb.worksheets:
            cell_a3 = sheet['A3']
            val = cell_a3.value

            # Blank/null is acceptable
            if val is None or str(val).strip() == '':
                return {
                    'pass': True,
                    'score': 1.0,
                    'feedback': f'A3 in {xlsx_file.name} is blank/null (acceptable per rubric)'
                }

            val_str = str(val).strip().upper()

            # Check if A3 contains ANY ONE of the 9 claim IDs
            for rid in required_ids:
                if rid.upper() in val_str:
                    return {
                        'pass': True,
                        'score': 1.0,
                        'feedback': f'A3 in {xlsx_file.name} contains claim ID {rid}. Value: {str(val)[:200]}'
                    }

            # Flexible match: without hyphen
            for rid in required_ids:
                rid_nohyphen = rid.replace('-', '')
                if rid_nohyphen in val_str.replace('-', '').replace(' ', ''):
                    return {
                        'pass': True,
                        'score': 1.0,
                        'feedback': f'A3 in {xlsx_file.name} contains claim ID {rid} (flexible match). Value: {str(val)[:200]}'
                    }

            # Also scan other cells in row 3 in case the agent put the ID in a different column
            max_col = sheet.max_column if sheet.max_column else 20
            for col in range(1, max_col + 1):
                cell_val = sheet.cell(row=3, column=col).value
                if cell_val is not None:
                    cell_str = str(cell_val).strip().upper()
                    for rid in required_ids:
                        if rid.upper() in cell_str:
                            return {
                                'pass': True,
                                'score': 0.8,
                                'feedback': f'Claim ID {rid} found in row 3 column {col} of {xlsx_file.name} (not A3, but close). Value: {cell_str[:200]}'
                            }

            # This file's A3 does not match — record as best failure but keep checking other files
            best_result = {
                'pass': False,
                'score': 0.0,
                'feedback': f'A3 in {xlsx_file.name} is not blank/null and does not contain any of the 9 required claim IDs. A3 value: {str(val)[:300]}'
            }
            # NOTE: do NOT return here — continue to next file

    return best_result

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    paths_to_check = []
    if external_services_path:
        paths_to_check.append(Path(external_services_path) / 'mailbox.json')
    paths_to_check.append(Path(workspace_path) / 'mailbox.json')

    mailbox_found = False
    all_emails_info = []

    for mailbox_path in paths_to_check:
        if not mailbox_path.exists():
            continue
        mailbox_found = True
        try:
            with open(mailbox_path) as f:
                data = json.load(f)
            emails = data.get('emails', [])
            for email in emails:
                folder = (email.get('folder', '') or '').lower()
                to_addr = (email.get('to_addr', '') or email.get('to', '') or '').lower()
                subject = (email.get('subject', '') or '').lower()
                body_text = (email.get('body_text', '') or email.get('body', '') or '').lower()

                is_sent = 'sent' in folder
                is_to_joe = 'joem@pathfinder.com' in to_addr

                if is_sent and is_to_joe:
                    all_emails_info.append({
                        'to': to_addr,
                        'subject': subject[:80],
                        'folder': folder
                    })
                    return {
                        'pass': True,
                        'score': 1.0,
                        'feedback': f'Found sent email to joem@pathfinder.com. Subject: {subject[:80]}'
                    }

        except Exception as e:
            continue

    if not mailbox_found:
        return {'pass': False, 'score': 0.0, 'feedback': 'mailbox.json not found or unreadable in either workspace or external services path.'}

    detail = ''
    if all_emails_info:
        detail = f' Found {len(all_emails_info)} email(s) but none were in the Sent folder addressed to joem@pathfinder.com. Email snippets: {json.dumps(all_emails_info[:3])}'
    else:
        detail = ' No sent emails to joem@pathfinder.com were found at all.'

    return {
        'pass': False,
        'score': 0.0,
        'feedback': f'No email to joem@pathfinder.com found in the Sent folder.{detail}'
    }

from pathlib import Path
import openpyxl
import re
import datetime as dt


def verify(workspace_path, external_services_path=None):
    # Search for the file flexibly
    target_file = Path(workspace_path) / "PBC_RA_Queue.xlsx"
    if not target_file.exists():
        candidates = list(Path(workspace_path).rglob("PBC_RA_Queue.xlsx"))
        if not candidates:
            # Also try case-insensitive
            candidates = [p for p in Path(workspace_path).rglob("*.xlsx") if "pbc_ra_queue" in p.name.lower()]
        if not candidates:
            return {"pass": False, "score": 0.0, "feedback": "File PBC_RA_Queue.xlsx not found in workspace."}
        target_file = candidates[0]

    try:
        wb = openpyxl.load_workbook(str(target_file), data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open PBC_RA_Queue.xlsx: {e}"}

    ws = wb.active

    expected_claim_ids = {
        "HIC-19887899", "HIC-19887900", "HIC-19887901",
        "HIC-25124778", "HIC-25124779", "HIC-25124780",
        "HIC-26877757", "HIC-26877758", "HIC-26877795"
    }

    # Scan the entire sheet to find claim entries, being very flexible about location
    found_claims = {}
    detail_msgs = []

    # Scan broadly
    max_row = max(ws.max_row or 1, 50)
    max_col = max(ws.max_column or 1, 20)

    for row_num in range(1, max_row + 1):
        row_values = []
        for col in range(1, max_col + 1):
            cell_val = ws.cell(row=row_num, column=col).value
            row_values.append(cell_val)

        # Try to find a claim ID in this row
        claim_id_found = None
        for col_idx, val in enumerate(row_values):
            if val is not None:
                val_str = str(val).strip().upper()
                for cid in expected_claim_ids:
                    if val_str == cid.upper():
                        claim_id_found = cid
                        break
                    # Also try without hyphen
                    if val_str.replace("-", "").replace(" ", "") == cid.replace("-", ""):
                        claim_id_found = cid
                        break
            if claim_id_found:
                break

        if claim_id_found is None:
            continue

        if claim_id_found in found_claims:
            continue  # Already found this claim

        # Check all cells in the row for trigger, trigger_date, staff_assigned, status
        trigger_ok = False
        trigger_date_ok = False
        staff_ok = False
        status_ok = False

        for col_idx, val in enumerate(row_values):
            if val is None:
                continue
            val_str = str(val).strip()

            # Check trigger - accept CO-45, CO 45, CO45, co-45, etc.
            if re.match(r'^CO[\s\-]?45$', val_str, re.IGNORECASE):
                trigger_ok = True

            # Check trigger_date - accept various date formats for 02/17/2026
            if _is_matching_date(val, 2026, 2, 17):
                trigger_date_ok = True

            # Check staff_assigned - Joe Malfroy
            normalized = val_str.lower().replace(" ", "").replace(",", "").replace(".", "")
            if "joemalfroy" in normalized or "malfroyj" in normalized:
                staff_ok = True
            if "malfroy" in val_str.lower() and "joe" in val_str.lower():
                staff_ok = True

            # Check status - Open
            if val_str.lower().strip() == "open":
                status_ok = True

        found_claims[claim_id_found] = {
            "row": row_num,
            "trigger_ok": trigger_ok,
            "trigger_date_ok": trigger_date_ok,
            "staff_ok": staff_ok,
            "status_ok": status_ok,
            "row_values": row_values[:max_col]
        }

    # Evaluate results
    total_pass = 0
    total_partial = 0

    for cid in sorted(expected_claim_ids):
        if cid not in found_claims:
            detail_msgs.append(f"MISSING: {cid} not found anywhere in the sheet.")
        else:
            info = found_claims[cid]
            row_issues = []
            checks_passed = 0
            total_checks = 4

            if info["trigger_ok"]:
                checks_passed += 1
            else:
                row_issues.append("trigger not 'CO-45'")

            if info["trigger_date_ok"]:
