def _is_matching_date(val, year, month, day):
    if val is None:
        return False
    if isinstance(val, (dt.datetime, dt.date)):
        return val.year == year and val.month == month and val.day == day
    return bool(re.search(r'0?2[/\-]17[/\-]2026', str(val).strip()))

