            return {"pass": False, "score": 0.0, "feedback": f"File not found: {file_path}"}

    try:
        wb = openpyxl.load_workbook(str(file_path), data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to open workbook: {e}"}

    # Use the active sheet or first sheet
    ws = wb.active

    non_zero_cells = []
    total_cells = 0
    zero_cells = 0

    # Rubric says K14 through M22: Columns K=11, L=12, M=13; Rows 14-22
    for row in range(14, 23):  # 14 through 22 inclusive
        for col_letter, col_idx in [('K', 11), ('L', 12), ('M', 13)]:
            total_cells += 1
            cell = ws.cell(row=row, column=col_idx)
            val = cell.value

            # Check if the value is effectively 0
            is_zero = False
            if val is None or val == '' or val == 0:
                is_zero = True
            elif isinstance(val, (int, float)):
                if abs(val) < 0.001:  # tolerance for floating point
                    is_zero = True
            elif isinstance(val, str):
                stripped = val.strip().replace('$', '').replace(',', '').replace(' ', '')
                if stripped == '' or stripped == '0' or stripped == '0.00' or stripped == '0.0':
                    is_zero = True
                else:
                    try:
                        numeric = float(stripped)
                        if abs(numeric) < 0.001:
                            is_zero = True
                    except ValueError:
                        pass

            if is_zero:
                zero_cells += 1
            else:
                non_zero_cells.append(f"{col_letter}{row}={val}")

    wb.close()

    if not non_zero_cells:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"All {total_cells} cells in K14:M22 are 0 as required."
        }
    else:
        score = zero_cells / total_cells if total_cells > 0 else 0.0
        return {
            "pass": False,
            "score": score,
            "feedback": f"{len(non_zero_cells)} cell(s) in K14:M22 are not 0: {', '.join(non_zero_cells)}"
        }

