from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    # We need to check mailbox.json for a draft email with the specified subject.
    # mailbox.json could be in the workspace or in external_services_path.

    mailbox_path = None
    candidates = []

    # Check external_services_path first
    if external_services_path:
        candidates.append(Path(external_services_path) / "mailbox.json")

    # Also check workspace_path
    candidates.append(Path(workspace_path) / "mailbox.json")

    for candidate in candidates:
        if candidate.exists():
            mailbox_path = candidate
            break

    if mailbox_path is None:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": "Could not find mailbox.json in either external_services_path or workspace_path."
        }

    try:
        with open(mailbox_path, 'r', encoding='utf-8') as f:
            mailbox_data = json.load(f)
    except Exception as e:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"Error reading mailbox.json: {e}"
        }

    emails = mailbox_data.get("emails", [])
    if not emails:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": "No emails found in mailbox.json."
        }

    expected_subject = "Contractual Rate Dispute Hull Insurance / A4789P / CPT 11241"
    expected_subject_lower = expected_subject.lower().strip()

    # Also create a more flexible pattern: just check key components are present
    key_components = ["contractual rate dispute", "hull insurance", "a4789p", "cpt 11241"]

    draft_emails = []
    matching_drafts = []
    all_subjects = []

    for email in emails:
        subject = email.get("subject", "").strip()
        folder = email.get("folder", "").strip()
        all_subjects.append(f"[folder={folder}] {subject}")

        # Check if it's a draft
        is_draft = folder.lower() in ["drafts", "draft"]

        if is_draft:
            draft_emails.append(email)

        # Check subject match - be generous
        subject_lower = subject.lower().strip()

        # Exact match (case-insensitive)
        exact_match = (subject_lower == expected_subject_lower)

        # Flexible match: normalize slashes and whitespace
        def normalize(s):
            s = re.sub(r'\s*/\s*', ' / ', s)
            s = re.sub(r'\s+', ' ', s)
            return s.strip().lower()

        normalized_match = (normalize(subject) == normalize(expected_subject))

        # Component match: all key components present
        component_match = all(comp in subject_lower for comp in key_components)

        if exact_match or normalized_match or component_match:
            if is_draft:
                matching_drafts.append(email)
            # Be lenient: even if not explicitly in "Drafts" folder, if the subject matches
            # and the task says "do not send", it might be in another folder
            elif not is_draft:
                # Still track it but note it's not in Drafts
                matching_drafts.append(email)  # Be generous

    if matching_drafts:
        found_email = matching_drafts[0]
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"Found email with matching subject: \"{found_email.get('subject', '')}\" in folder \"{found_email.get('folder', '')}\""
        }

    return {
        "pass": False,
        "score": 0.0,
        "feedback": f"No email found with subject matching 'Contractual Rate Dispute Hull Insurance / A4789P / CPT 11241'. Found {len(draft_emails)} draft(s). All email subjects: {all_subjects}"
    }

